int MotorSpeed = 0;         // variable to store the motor speed
int MotorDirection = 0;     // variable to store the motor direction

void setup() {
  // Set the stepper motor pins as outputs
  pinMode(StepPin, OUTPUT);
  pinMode(DirPin, OUTPUT);
  pinMode(EnablePin, OUTPUT);

  // Set the potentiometer pin as input
  pinMode(PotPin, INPUT);

  // Enable the stepper motor
  digitalWrite(EnablePin, LOW);
}

void loop() {
  // Read the potentiometer value
  PotValue = analogRead(PotPin);

  // Map the potentiometer value to motor speed (0-500 RPM)
  MotorSpeed = map(PotValue, 0, 1023, 0, 500);

  // Set the motor direction based on the potentiometer value
  if (PotValue < 512) {
    MotorDirection = 0;     // clockwise
  }
  else {
    MotorDirection = 1;     // counter-clockwise
  }

  // Set the direction of the stepper motor
  Motor.setSpeedDirection(MotorSpeed, MotorDirection);

  // Run the stepper motor continuously
  Motor.runContinuously();
}
```

